import React, { useMemo, useState } from "react";

const DUMMY_SYSTEMS = [
  {
    id: "SYS-1001",
    owner: "Manufacturing / Line A",
    healthScore: 92,
    status: "healthy",
    primaryRootCause: "Hardware",
  },
  {
    id: "SYS-1002",
    owner: "Data Center / Rack 7",
    healthScore: 64,
    status: "warning",
    primaryRootCause: "Software",
  },
  {
    id: "SYS-1003",
    owner: "Field Device / Pump 4",
    healthScore: 38,
    status: "critical",
    primaryRootCause: "Security",
  },
];

function statusBadge(status) {
  switch (status) {
    case "healthy":
      return "bg-green-100 text-green-700";
    case "warning":
      return "bg-yellow-100 text-yellow-700";
    case "critical":
      return "bg-red-100 text-red-700";
    default:
      return "bg-gray-100 text-gray-700";
  }
}

export default function SystemsOverview({ openSystem }) {

  const [statusFilter, setStatusFilter] = useState("All");

  const filtered = useMemo(() => {
    return DUMMY_SYSTEMS.filter((s) => {
      if (statusFilter !== "All" && s.status !== statusFilter.toLowerCase())
        return false;
      return true;
    });
  }, [statusFilter]);

  return (
    <div className="space-y-6">

      {/* HEADER */}
      <div className="flex flex-col md:flex-row md:justify-between gap-4">

        <div>
          <h1 className="text-2xl font-semibold">Systems Overview</h1>
          <p className="text-sm text-gray-500">
            AI evaluated system health across all devices
          </p>
        </div>

        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="border px-3 py-2 rounded-md text-sm"
        >
          <option>All</option>
          <option>Healthy</option>
          <option>Warning</option>
          <option>Critical</option>
        </select>

      </div>


      {/* SYSTEM CARDS */}

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">

        {filtered.map((system) => (

          <div
            key={system.id}
            className="bg-white border rounded-xl p-5 shadow-sm hover:shadow-md transition"
          >

            {/* HEADER */}

            <div className="flex justify-between items-center mb-3">

              <h3 className="font-semibold text-gray-900">
                {system.id}
              </h3>

              <span
                className={`px-2 py-1 rounded-full text-xs font-medium ${statusBadge(
                  system.status
                )}`}
              >
                {system.status}
              </span>

            </div>

            <p className="text-sm text-gray-500 mb-4">
              {system.owner}
            </p>


            {/* HEALTH */}

            <div className="mb-4">

              <div className="text-sm text-gray-500">
                Health Score
              </div>

              <div className="text-2xl font-bold">
                {system.healthScore}
              </div>

            </div>


            {/* ROOT CAUSE */}

            <div className="text-sm text-gray-600 mb-4">
              Root Cause:{" "}
              <span className="font-medium">
                {system.primaryRootCause}
              </span>
            </div>


            {/* ACTIONS */}

            <div className="flex gap-3">

              <button
                onClick={() => openSystem(system)}
                className="flex-1 px-3 py-2 border rounded-md text-sm hover:bg-gray-100"
              >
                Details
              </button>

              <button
                className="flex-1 px-3 py-2 bg-blue-600 text-white rounded-md text-sm hover:bg-blue-700"
              >
                Assign
              </button>

            </div>

          </div>

        ))}

      </div>

    </div>
  );
}
